def rle_encode(s: str) -> str:
    if not s:
        return ""

    encoded = []
    count = 1
    prev_char = s[0]

    for char in s[1:]:
        if char == prev_char:
            count += 1
        else:
            encoded.append(f"{prev_char}{count}")
            prev_char = char
            count = 1
    encoded.append(f"{prev_char}{count}")

    return "".join(encoded)

print(rle_encode('aaabb'))
